mapper.select:
SELECT q.*, u.username as username, u.avatar as user_avatar, c.name as category_name FROM question q LEFT JOIN user u ON q.user_id = u.id LEFT JOIN category c ON q.category_id = c.id
AND (q.title LIKE CONCAT('%', #{keyword}, '%') OR q.content LIKE CONCAT('%', #{keyword}, '%'))
AND q.category_id = #{categoryId}
ORDER BY q.created_at DESC LIMIT #{offset}, #{size}
